package com.socialblog.follower.domain;import jakarta.persistence.*;import java.time.Instant;import java.util.UUID;@Entity @Table(name="user_projection")public class UserProjection{@Id @Column(name="user_id")private UUID id;@Column(nullable=false)private boolean active;@Column(name="display_name",length=80)private String displayName;@Column(name="updated_at",nullable=false)private Instant updatedAt;protected UserProjection(){}public UserProjection(UUID id,boolean active,String name){this.id=id;update(active,name);}public void update(boolean value,String name){active=value;displayName=name;updatedAt=Instant.now();}public UUID getId(){return id;}public boolean isActive(){return active;}public String getDisplayName(){return displayName;}}
